logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Environment variables expected (set per-function for customization):
#   SERVICE_NAME       - Name of this specific microservice
#   DYNAMODB_TABLE     - DynamoDB table this function primarily uses
#   S3_BUCKET          - S3 bucket this function primarily uses
#   SNS_TOPIC_ARN      - SNS topic for publishing events
#   SQS_QUEUE_URL      - SQS queue URL for messaging
#   ENVIRONMENT        - dev / staging / prod

SERVICE_NAME = os.environ.get("SERVICE_NAME", "unknown-service")
DYNAMODB_TABLE = os.environ.get("DYNAMODB_TABLE", "myapp-default-table")
S3_BUCKET = os.environ.get("S3_BUCKET", "myapp-microservices-default")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "")
SQS_QUEUE_URL = os.environ.get("SQS_QUEUE_URL", "")
ENVIRONMENT = os.environ.get("ENVIRONMENT", "dev")


class ServiceClients:
    """Lazy-initialized shared AWS service clients."""
    _dynamodb = None
    _s3 = None
    _sns = None
    _sqs = None

    @classmethod
    def dynamodb(cls):
        if cls._dynamodb is None:
            cls._dynamodb = boto3.resource("dynamodb")
        return cls._dynamodb

    @classmethod
    def s3(cls):
        if cls._s3 is None:
            cls._s3 = boto3.client("s3")
        return cls._s3

    @classmethod
    def sns(cls):
        if cls._sns is None:
            cls._sns = boto3.client("sns")
        return cls._sns

    @classmethod
    def sqs(cls):
        if cls._sqs is None:
            cls._sqs = boto3.client("sqs")
        return cls._sqs


def build_response(status_code, body, headers=None):
    """Standardized API Gateway response builder."""
    default_headers = {
        "Content-Type": "application/json",
        "X-Service-Name": SERVICE_NAME,
        "Access-Control-Allow-Origin": "*",
        "Access-Control-Allow-Methods": "GET,POST,PUT,DELETE,OPTIONS",
        "Access-Control-Allow-Headers": "Content-Type,Authorization",
    }
    if headers:
        default_headers.update(headers)

    return {
        "statusCode": status_code,
        "headers": default_headers,
        "body": json.dumps(body, default=str),
    }


def publish_event(event_type, payload):
    """Publish a domain event to SNS for other microservices to consume."""
    if not SNS_TOPIC_ARN:
        logger.warning("SNS_TOPIC_ARN not configured; skipping event publish")
        return None

    message = {
        "eventType": event_type,
        "serviceName": SERVICE_NAME,
        "environment": ENVIRONMENT,
        "timestamp": datetime.utcnow().isoformat() + "Z",
        "payload": payload,
    }

    response = ServiceClients.sns().publish(
        TopicArn=SNS_TOPIC_ARN,
        Message=json.dumps(message, default=str),
        MessageAttributes={
            "eventType": {"DataType": "String", "StringValue": event_type},
            "serviceName": {"DataType": "String", "StringValue": SERVICE_NAME},
        },
    )
    logger.info(f"Published event '{event_type}' with MessageId: {response['MessageId']}")
    return response


def send_to_queue(message_body, delay_seconds=0):
    """Send a message to SQS for async processing."""
    if not SQS_QUEUE_URL:
        logger.warning("SQS_QUEUE_URL not configured; skipping queue send")
        return None

    response = ServiceClients.sqs().send_message(
        QueueUrl=SQS_QUEUE_URL,
        MessageBody=json.dumps(message_body, default=str),
        DelaySeconds=delay_seconds,
        MessageAttributes={
            "ServiceName": {"DataType": "String", "StringValue": SERVICE_NAME},
        },
    )
    logger.info(f"Sent message to SQS with MessageId: {response['MessageId']}")
    return response


def store_to_dynamodb(item):
    """Store an item in the configured DynamoDB table."""
    table = ServiceClients.dynamodb().Table(DYNAMODB_TABLE)
    item["updatedAt"] = datetime.utcnow().isoformat() + "Z"
    item["serviceName"] = SERVICE_NAME
    response = table.put_item(Item=item)
    logger.info(f"Stored item in DynamoDB table '{DYNAMODB_TABLE}'")
    return response


def get_from_dynamodb(key):
    """Retrieve an item from the configured DynamoDB table."""
    table = ServiceClients.dynamodb().Table(DYNAMODB_TABLE)
    response = table.get_item(Key=key)
    item = response.get("Item")
    if item:
        logger.info(f"Retrieved item from DynamoDB: {key}")
    else:
        logger.info(f"Item not found in DynamoDB: {key}")
    return item


def store_to_s3(key, body, content_type="application/json"):
    """Store an object in the configured S3 bucket."""
    if isinstance(body, (dict, list)):
        body = json.dumps(body, default=str)

    ServiceClients.s3().put_object(
        Bucket=S3_BUCKET,
        Key=key,
        Body=body.encode("utf-8") if isinstance(body, str) else body,
        ContentType=content_type,
        Metadata={"service-name": SERVICE_NAME, "environment": ENVIRONMENT},
    )
    logger.info(f"Stored object to S3: s3://{S3_BUCKET}/{key}")


def get_from_s3(key):
    """Retrieve an object from the configured S3 bucket."""
    response = ServiceClients.s3().get_object(Bucket=S3_BUCKET, Key=key)
    body = response["Body"].read().decode("utf-8")
    logger.info(f"Retrieved object from S3: s3://{S3_BUCKET}/{key}")
    return body


# =============================================================================
# Lambda Handler - Example: Order Processing Microservice
# =============================================================================
# This handler demonstrates how a microservice uses the shared IAM role to
# interact with S3, DynamoDB, SNS, and SQS. Each of the 10+ Lambda functions
# follows the same pattern with the same role ARN.
# =============================================================================

def handle_api_gateway_event(event):
    """Handle incoming API Gateway (REST/HTTP) requests."""
    http_method = event.get("httpMethod", event.get("requestContext", {}).get("http", {}).get("method", "GET"))
    path = event.get("path", event.get("rawPath", "/"))
    body = json.loads(event.get("body", "{}") or "{}")

    logger.info(f"API request: {http_method} {path}")

    if http_method == "POST" and "/orders" in path:
        order_id = f"ORD-{datetime.utcnow().strftime('%Y%m%d%H%M%S%f')}"
        order = {
            "orderId": order_id,
            "status": "CREATED",
            "createdAt": datetime.utcnow().isoformat() + "Z",
            **body,
        }

        # Store in DynamoDB
        store_to_dynamodb(order)

        # Archive to S3
        s3_key = f"orders/{datetime.utcnow().strftime('%Y/%m/%d')}/{order_id}.json"
        store_to_s3(s3_key, order)

        # Publish event for other microservices
        publish_event("ORDER_CREATED", {"orderId": order_id, "customerId": body.get("customerId")})

        # Queue for async fulfillment processing
        send_to_queue({"action": "PROCESS_ORDER", "orderId": order_id}, delay_seconds=5)

        return build_response(201, {"message": "Order created", "orderId": order_id})

    elif http_method == "GET" and "/orders/" in path:
        order_id = path.split("/orders/")[-1].strip("/")
        if not order_id:
            return build_response(400, {"error": "Missing orderId"})

        item = get_from_dynamodb({"orderId": order_id})
        if item:
            return build_response(200, item)
        return build_response(404, {"error": "Order not found"})

    elif http_method == "GET" and "/health" in path:
        return build_response(200, {
            "service": SERVICE_NAME,
            "status": "healthy",
            "environment": ENVIRONMENT,
            "timestamp": datetime.utcnow().isoformat() + "Z",
        })

    return build_response(400, {"error": f"Unsupported route: {http_method} {path}"})


def handle_sqs_event(event):
    """Handle SQS messages for async processing."""
    results = []
    for record in event.get("Records", []):
        message_body = json.loads(record.get("body", "{}"))
        message_id = record.get("messageId", "unknown")
        logger.info(f"Processing SQS message {message_id}: {message_body}")

        action = message_body.get("action")

        if action == "PROCESS_ORDER":
            order_id = message_body.get("orderId")
            order = get_from_dynamodb({"orderId": order_id})
            if order:
                order["status"] = "PROCESSING"
                store_to_dynamodb(order)
                publish_event("ORDER_PROCESSING", {"orderId": order_id})
                results.append({"messageId": message_id, "status": "processed"})
            else:
                logger.error(f"Order {order_id} not found for processing")
                results.append({"messageId": message_id, "status": "error", "reason": "order_not_found"})
        else:
            logger.warning(f"Unknown action: {action}")
            results.append({"messageId": message_id, "status": "skipped"})

    return {"batchItemFailures": []}


def handle_sns_event(event):
    """Handle SNS notifications from other microservices."""
    for record in event.get("Records", []):
        sns_message = record.get("Sns", {})
        subject = sns_message.get("Subject", "")
        message = json.loads(sns_message.get("Message", "{}"))
        event_type = message.get("eventType", "UNKNOWN")
        source_service = message.get("serviceName", "unknown")

        logger.info(f"Received SNS event '{event_type}' from '{source_service}'")

        # React to events from other microservices
        if event_type == "PAYMENT_COMPLETED":
            order_id = message.get("payload", {}).get("orderId")
            if order_id:
                order = get_from_dynamodb({"orderId": order_id})
                if order:
                    order["status"] = "PAID"
                    order["paidAt"] = datetime.utcnow().isoformat() + "Z"
                    store_to_dynamodb(order)
                    publish_event("ORDER_PAID", {"orderId": order_id})

        elif event_type == "INVENTORY_RESERVED":
            order_id = message.get("payload", {}).get("orderId")
            if order_id:
                order = get_from_dynamodb({"orderId": order_id})
                if order:
                    order["status"] = "READY_TO_SHIP"
                    store_to_dynamodb(order)
                    publish_event("ORDER_READY_TO_SHIP", {"orderId": order_id})

    return {"statusCode": 200}


def handle_s3_event(event):
    """Handle S3 event notifications."""
    for record in event.get("Records", []):
        bucket = record.get("s3", {}).get("bucket", {}).get("name")
        key = record.get("s3", {}).get("object", {}).get("key")
        event_name = record.get("eventName", "")

        logger.info(f"S3 event '{event_name}' on s3://{bucket}/{key}")

        if "ObjectCreated" in event_name and key.endswith(".json"):
            content = get_from_s3(key)
            data = json.loads(content)
            logger.info(f"Processed S3 object with {len(data)} keys")

    return {"statusCode": 200}


def detect_event_source(event):
    """Detect the source of the Lambda invocation."""
    if "Records" in event:
        first_record = event["Records"][0]
        if "eventSource" in first_record:
            source = first_record["eventSource"]
            if source == "aws:sqs":
                return "sqs"
            elif source == "aws:s3":
                return "s3"
        if "Sns" in first_record:
            return "sns"

    if "httpMethod" in event or "requestContext" in event:
        return "api_gateway"

    if "source" in event and event["source"] == "aws.events":
        return "eventbridge"

    return "direct"


def lambda_handler(event, context):
    """
    Main Lambda handler for the microservice.

    This function uses the shared IAM role:
      arn:aws:iam::<ACCOUNT_ID>:role/shared-microservices-lambda-execution-role

    All 10+ Lambda functions in the architecture reference this same role,
    reducing IAM role sprawl while maintaining consistent permissions across:
      - S3 (object storage and archival)
      - DynamoDB (primary data store)
      - SNS (event publishing for inter-service communication)
      - SQS (async message processing)
      - CloudWatch Logs (logging and monitoring)
      - X-Ray (distributed tracing)
    """
    request_id = context.aws_request_id if context else "local"
    logger.info(f"[{SERVICE_NAME}] Invocation started | RequestId: {request_id}")

    try:
        event_source = detect_event_source(event)
        logger.info(f"Detected event source: {event_source}")

        if event_source == "api_gateway":
            return handle_api_gateway_event(event)
        elif event_source == "sqs":
            return handle_sqs_event(event)
        elif event_source == "sns":
            return handle_sns_event(event)
        elif event_source == "s3":
            return handle_s3_event(event)
        elif event_source == "eventbridge":
            logger.info("EventBridge scheduled invocation - running maintenance tasks")
            return build_response(200, {"message": "Maintenance complete"})
        else:
            # Direct invocation
            logger.info(f"Direct invocation with payload: {json.dumps(event, default=str)[:500]}")
            return {
                "statusCode": 200,
                "service": SERVICE_NAME,
                "message": "Direct invocation processed",
                "timestamp": datetime.utcnow().isoformat() + "Z",
            }

    except boto3.exceptions.Boto3Error as e:
        logger.error(f"AWS service error: {str(e)}", exc_info=True)
        return build_response(502, {
            "error": "AWS service error",
            "message": str(e),
            "service": SERVICE_NAME,
        })
    except json.JSONDecodeError as e:
        logger.error(f"JSON parsing error: {str(e)}", exc_info=True)
        return build_response(400, {
            "error": "Invalid JSON",
            "message": str(e),
        })
    except Exception as e:
        logger.error(f"Unhandled error: {str(e)}", exc_info=True)
        return build_response(500, {
            "error": "Internal server error",
            "message": str(e),
            "service": SERVICE_NAME,
            "requestId": request_id,
        })


